// Array sebagai sumber data (sementara, akan pindah ke LocalStorage di P10)
let articles = [];

// ===== FUNGSI RENDER — Dipanggil setiap kali data berubah =====
function renderTable() {
  // Selalu bersihkan dulu sebelum render ulang
  tableBody.innerHTML = '';

  // Handle empty state
  if (articles.length === 0) {
    tableBody.innerHTML = `
      <tr>
        <td colspan="4" style="text-align:center; color:#94a3b8; padding:2rem">
          Belum ada artikel. Tambahkan artikel pertama Anda!
        </td>
      </tr>
    `;
    return;
  }

  // Render setiap item dari array menggunakan forEach
  articles.forEach((article, index) => {
    const row = document.createElement('tr');
    row.innerHTML = `
      <td>${index + 1}</td>
      <td>${article.title}</td>
      <td>${article.content.substring(0, 80)}...</td>
      <td>
        <button onclick="setupEdit(${article.id})"   class="btn-primary" >Edit</button>
        <button onclick="deleteArticle(${article.id})" class="btn-danger"  >Hapus</button>
      </td>
    `;
    tableBody.appendChild(row);
  });
}

// ===== TAMBAH DATA (CREATE) =====
articleForm.addEventListener('submit', function(e) {
  e.preventDefault();

  const title   = inputTitle.value.trim();
  const content = inputContent.value.trim();

  // Validasi: jangan izinkan data kosong
  if (!title) {
    showToast('Judul artikel wajib diisi!', 'error');
    inputTitle.focus(); // Kembalikan fokus ke field yang bermasalah
    return;
  }
  if (!content) {
    showToast('Konten artikel wajib diisi!', 'error');
    inputContent.focus();
    return;
  }

  // Buat object artikel baru
  const newArticle = {
    id      : Date.now(),        // ID unik berbasis timestamp
    title   : title,
    content : content,
    createdAt: new Date().toLocaleDateString('id-ID')
  };

  articles.push(newArticle);   // Tambahkan ke array
  renderTable();                // Render ulang tabel
  clearForm();                  // Bersihkan form
  showToast('Artikel berhasil ditambahkan!');
});

// ===== UTILITY FUNCTIONS =====
function clearForm() {
  inputTitle.value   = '';
  inputContent.value = '';
  inputTitle.focus(); // Siap untuk input berikutnya
}

// ===== HAPUS DATA (DELETE) =====
function deleteArticle(id) {
  // Filter: buat array baru tanpa item yang ID-nya cocok
  articles = articles.filter(a => a.id !== id);
  renderTable();
  showToast('Artikel berhasil dihapus!', 'success');
}

// ===== INISIALISASI =====
renderTable(); // Panggil saat load untuk tampilkan empty state
